mapper.select:
SELECT email_id, email, email_type, subject, content, code,
       send_status, send_time, expire_time, create_time
FROM email_record
WHERE email = #{email}

    AND email_type = #{emailType}

ORDER BY create_time DESC

mapper.update:
UPDATE email_record
SET send_status = #{sendStatus}
WHERE email_id = #{emailId}
